import { useEffect, useState } from 'react';

/**
 * This hook takes an expiration time and returns the expired state when the expiration time is reached.
 * If the expiration time isn't provided, or isn't reached yet, the default state is returned.
 * By default, the hook returns a boolean indicating whether the expiration time has been reached or not,
 * but you can also provide custom states for both cases.
 */
export function useExpiredState<T = boolean>(
  expiresAt?: number | null,
  defaultState: T = false as T,
  expiredState: T = true as T
) {
  const diff = !Number.isFinite(expiresAt) ? Number.POSITIVE_INFINITY : expiresAt! - Date.now();
  const isExpired = !!expiresAt && diff <= 0;
  const [, rerender] = useState({});

  useEffect(() => {
    if (!Number.isFinite(expiresAt)) return;
    const diff = expiresAt! - Date.now();
    if (diff <= 0) return;

    const timeout = setTimeout(() => rerender({}), diff);
    return () => clearTimeout(timeout);
  }, [expiresAt]);

  return isExpired ? expiredState : defaultState;
}
